example.code:
stage('Test') {
    parallel {
        stage('Unit Tests') {
            steps { container('node') { sh 'npm run test:unit -- --coverage' } }
            post { always { junit 'junit.xml' } }
        }
        stage('Integration Tests') {
            steps { container('node') { sh 'npm run test:integration' } }
        }
        stage('Security Scan') {
            steps { container('node') { sh 'npm audit --audit-level=high' } }
        }
    }
}

stage('Deploy to Production') {
    when { branch 'main' }
    input {
        message "Deploy to production?"
        ok "Deploy"
        submitter "admin,deployers"
    }
    steps { /* kubectl apply */ }
}
